### `debounce` 函数 —— 标准实现

```javascript
/**
 * 创建一个防抖函数，在最后一次调用后的 wait 毫秒后执行。
 *
 * @param {Function} fn       要防抖的函数
 * @param {number}   wait     等待时间（毫秒）
 * @param {boolean}  [immediate=false] 是否在第一次调用时立即执行（leading edge）
 * @returns {Function} 防抖后的函数（附带 .cancel() 和 .flush()）
 */
function debounce(fn, wait, immediate = false) {
  let timer = null;
  let lastArgs = null;
  let lastThis = null;
  let result = undefined;
  let called = false; // 记录 immediate 模式下是否已调用过

  const later = () => {
    timer = null;
    if (!immediate) {
      result = fn.apply(lastThis, lastArgs);
      lastArgs = lastThis = null;
    }
  };

  const debounced = function (...args) {
    lastArgs = args;
    lastThis = this;

    if (timer) clearTimeout(timer);

    if (immediate && !called) {
      // 首次调用立即执行
      result = fn.apply(this, args);
      called = true;
      // 设置冷却计时器，冷却结束后 reset called
      timer = setTimeout(() => {
        timer = null;
        called = false;
        lastArgs = lastThis = null;
      }, wait);
    } else {
      timer = setTimeout(later, wait);
    }

    return result;
  };

  /** 取消当前待执行的调用 */
  debounced.cancel = () => {
    if (timer) {
      clearTimeout(timer);
      timer = null;
    }
    called = false;
    lastArgs = lastThis = null;
  };

  /** 立即执行当前等待中的调用 */
  debounced.flush = () => {
    if (timer) {
      clearTimeout(timer);
      timer = null;
      if (lastArgs) {
        result = fn.apply(lastThis, lastArgs);
        lastArgs = lastThis = null;
      }
      called = false;
    }
    return result;
  };

  return debounced;
}
```

---

### 用法示例

```javascript
// 搜索框输入防抖——用户停止输入 300ms 后才发起请求
const search = debounce(
  (query) => fetch(`/api/search?q=${query}`),
  300
);
searchInput.addEventListener('input', (e) => search(e.target.value));
```

```javascript
// immediate 模式——点击按钮防重复提交，立刻执行但后续点击不生效直到冷却结束
const submit = debounce(
  () => sendForm(),
  1000,
  true
);
submitBtn.addEventListener('click', submit);
```

```javascript
// 取消 & 刷新
const log = debounce(() => console.log('hi'), 500);
log();
log.cancel();        // 撤销 pending 的调用
log.flush();         // 立即执行 pending 调用
```

---

### 核心思路

| 模式 | 行为 |
|------|------|
| **非 immediate**（默认） | 疯狂触发 → 每次重置计时器 → 停手 `wait` 毫秒后才执行 |
| **immediate** | 第一次直接执行，随后 `wait` 毫秒内的触发全部被忽略，冷却结束后下一次又立即执行 |

本质是一种**频率管制策略**：把高频事件的多个连续触发合并成一次执行，区别在于执行时机落在"末尾"（leading: false）还是"开头"（leading: true）。想像一下电梯——`immediate: false` 是等人到齐了才关门，`immediate: true` 是第一个进门的人按关门键，后面的人就进不来了。

